import React, { useRef, useState } from "react";
import Navbar from "./Navbar";
import Hero from "./Hero";
import HowItWorks from "./HowItWorks";
import AppPanel from "./AppPanel";
import { TechSection, Footer } from "./TechSection";
import "./global.css";

export default function App() {
  const appRef  = useRef(null);
  const howRef  = useRef(null);
  const [wallet, setWallet] = useState("");

  const scrollToApp = () => appRef.current?.scrollIntoView({ behavior: "smooth" });
  const scrollToHow = () => howRef.current?.scrollIntoView({ behavior: "smooth" });

  return (
      <div>
        <Navbar
            wallet={wallet}
            onLaunchApp={scrollToApp}
        />
        <Hero
            onLaunchApp={scrollToApp}
            onHowItWorks={scrollToHow}
        />
        <div ref={howRef}>
          <HowItWorks />
        </div>
        <TechSection />
        <AppPanel
            forwardRef={appRef}
            onWalletChange={setWallet}
        />
        <Footer onLaunchApp={scrollToApp} />
      </div>
  );
}
